import React from "react";
import { Outlet, Link, useLocation } from "react-router-dom";

const AdminLayout = () => {
  const location = useLocation();

  const navItems = [
    { name: "Tổng quan", path: "/admin/dashboard", icon: "📊" },
    { name: "Quản lý sản phẩm", path: "/admin/products", icon: "🛍️" },
    { name: "Quản lý đơn hàng", path: "/admin/orders", icon: "📦" },
    { name: "Quản lý danh mục", path: "/admin/categories", icon: "🗂️" },
    { name: "Quản lý người dùng", path: "/admin/users", icon: "👤" },
  ];

  const currentPage = location.pathname.replace("/admin/", "").toUpperCase();
  const isDashboard = location.pathname === "/admin/dashboard";

  return (
    <div className="flex min-h-screen font-sans bg-secondary">
      {/* Sidebar */}
      <aside className="w-64 bg-secondary border-r border-pink-200 p-5 flex flex-col">
  {/* Logo / Profile */}
  <Link
    to="/"
    className="flex items-center mb-6 p-2 rounded-lg hover:bg-primary/20 transition"
  >
    <div className="w-12 h-12 rounded-full bg-primary flex items-center justify-center text-white font-bold shadow">
      A
    </div>
    <div className="ml-3">
      <p className="text-sm font-semibold text-dark">Admin</p>
      <p className="text-xs text-pink-600">DTP Flower Shop</p>
    </div>
  </Link>

  {/* Navigation */}
  <nav className="flex flex-col gap-2 flex-1">
    {navItems.map((item) => {
      const isActive = location.pathname === item.path;
      return (
        <Link
          key={item.path}
          to={item.path}
          className={`flex items-center gap-2 px-4 py-2 rounded-lg font-medium transition-colors duration-200
            ${isActive ? "bg-primary/40 text-primary shadow-lg" : "text-dark hover:bg-primary/20 hover:text-primary"}
          `}
        >
          <span>{item.icon}</span>
          {item.name}
        </Link>
      );
    })}

    {/* Xem trang web */}
    <a
      href="/"
      target="_self"
      className="mt-auto block w-full text-center bg-primary text-white py-2 rounded-xl font-semibold shadow hover:bg-primary/90 transition"
    >
      🌸 Xem trang web
    </a>
  </nav>
</aside>


      {/* Main content */}
      <main
        className={`flex-1 p-6 overflow-y-auto transition-colors duration-300 ${
          isDashboard ? "bg-pink-50" : "bg-secondary"
        }`}
      >
        {/* Header */}
        <div className="flex justify-between items-center mb-6">
          <h1 className={`text-2xl font-semibold ${isDashboard ? "text-primary" : "text-dark"}`}>
            {currentPage || "Dashboard"}
          </h1>
        </div>

        {/* Page content card */}
        <div
          className={`p-6 rounded-2xl shadow-md min-h-[70vh] transition-colors duration-300 ${
            isDashboard ? "bg-white/90" : "bg-white"
          }`}
        >
          <Outlet />
        </div>
      </main>
    </div>
  );
};

export default AdminLayout;
